import sqlite3
import sys

class PhoneDirectory:
    def __init__(self, db_name='contacts.db'):
        self.connection = sqlite3.connect(db_name)
        self.cursor = self.connection.cursor()
        self.create_table()

    def create_table(self):
        self.cursor.execute('''
            CREATE TABLE IF NOT EXISTS contacts (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                name TEXT NOT NULL,
                phone TEXT,
                email TEXT
            );
        ''')
        self.connection.commit()

    def add_contact(self, name, phone, email):
        try:
            self.cursor.execute('''
                INSERT INTO contacts (name, phone, email) 
                VALUES (?, ?, ?);
            ''', (name, phone, email))
            self.connection.commit()
            print("Contact added successfully.")
        except sqlite3.Error as e:
            print(f"An error occurred: {e}")

    def retrieve_contact(self, name):
        try:
            self.cursor.execute('''
                SELECT * FROM contacts WHERE name = ?;
            ''', (name,))
            contact = self.cursor.fetchone()
            if contact:
                print(contact)
            else:
                print("Contact not found.")
        except sqlite3.Error as e:
            print(f"An error occurred: {e}")

    def update_contact(self, name, phone, email):
        try:
            self.cursor.execute('''
                UPDATE contacts 
                SET phone = ?, email = ?
                WHERE name = ?;
            ''', (phone, email, name))
            self.connection.commit()
            if self.cursor.rowcount:
                print("Contact updated successfully.")
            else:
                print("Contact not found.")
        except sqlite3.Error as e:
            print(f"An error occurred: {e}")

    def delete_contact(self, name):
        try:
            self.cursor.execute('''
                DELETE FROM contacts WHERE name = ?;
            ''', (name,))
            self.connection.commit()
            if self.cursor.rowcount:
                print("Contact deleted successfully.")
            else:
                print("Contact not found.")
        except sqlite3.Error as e:
            print(f"An error occurred: {e}")

    def list_contacts(self):
        try:
            self.cursor.execute('''
                SELECT * FROM contacts ORDER BY name;
            ''')
            for contact in self.cursor.fetchall():
                print(contact)
        except sqlite3.Error as e:
            print(f"An error occurred: {e}")

    def search_contacts(self, name):
        try:
            self.cursor.execute('''
                SELECT * FROM contacts WHERE name LIKE ?;
            ''', ('%' + name + '%',))
            results = self.cursor.fetchall()
            if results:
                for contact in results:
                    print(contact)
            else:
                print("No contacts found.")
        except sqlite3.Error as e:
            print(f"An error occurred: {e}")

    def close(self):
        self.connection.close()

def main():
    directory = PhoneDirectory()

    while True:
        print("\nPhone Directory CLI")
        print("1. Add contact")
        print("2. Retrieve contact")
        print("3. Update contact")
        print("4. Delete contact")
        print("5. List all contacts")
        print("6. Search contacts")
        print("7. Exit")

        choice = input("Select an option: ")
        if choice == '1':
            name = input("Enter name: ")
            phone = input("Enter phone number: ")
            email = input("Enter email address: ")
            directory.add_contact(name, phone, email)
        elif choice == '2':
            name = input("Enter name of the contact to retrieve: ")
            directory.retrieve_contact(name)
        elif choice == '3':
            name = input("Enter name of the contact to update: ")
            phone = input("Enter new phone number: ")
            email = input("Enter new email address: ")
            directory.update_contact(name, phone, email)
        elif choice == '4':
            name = input("Enter name of the contact to delete: ")
            directory.delete_contact(name)
        elif choice == '5':
            directory.list_contacts()
        elif choice == '6':
            name = input("Enter name to search: ")
            directory.search_contacts(name)
        elif choice == '7':
            directory.close()
            sys.exit()
        else:
            print("Invalid option, please try again.")

if __name__ == "__main__":
    main()
