import React, { useState } from 'react';
import { useQuery } from '@apollo/client';
import gql from 'graphql-tag';

const GET_FILTERED_PRODUCTS = gql`
  query GetFilteredProducts($category: String, $minPrice: Float, $maxPrice: Float, $rating: Int) {
    filteredProducts(category: $category, minPrice: $minPrice, maxPrice: $maxPrice, rating: $rating) {
      id
      name
      price
      rating
    }
  }
`;

const ProductFilter = () => {
  const [filters, setFilters] = useState({ category: '', minPrice: 0, maxPrice: 0, rating: 0 });

  const { loading, error, data } = useQuery(GET_FILTERED_PRODUCTS, {
    variables: {
      category: filters.category,
      minPrice: filters.minPrice,
      maxPrice: filters.maxPrice,
      rating: filters.rating,
    },
  });

  const handleFilterChange = (e) => {
    const { name, value } = e.target;
    setFilters({ ...filters, [name]: value });
  };

  if (loading) return <p>Loading...</p>;
  if (error) return <p>Error: {error.message}</p>;

  if (data.filteredProducts.length === 0) return <p>No products found</p>;

  return (
    <div>
      <div>
        <input type="text" name="category" placeholder="Category" value={filters.category} onChange={handleFilterChange} />
        <input type="number" name="minPrice" placeholder="Min Price" value={filters.minPrice} onChange={handleFilterChange} min="0" />
        <input type="number" name="maxPrice" placeholder="Max Price" value={filters.maxPrice} onChange={handleFilterChange} min="0" />
        <input type="number" name="rating" placeholder="Rating" value={filters.rating} onChange={handleFilterChange} min="0" max="5" />
      </div>
      <ul>
        {data.filteredProducts.map(product => (
          <li key={product.id}>{product.name} - ${product.price} - {product.rating} stars</li>
        ))}
      </ul>
    </div>
  );
};

export default ProductFilter;
