from flask import Flask, request, jsonify
from flask_sqlalchemy import SQLAlchemy
from flask_jwt_extended import JWTManager, jwt_required, get_jwt_identity
from flask_marshmallow import Marshmallow
from sqlalchemy.exc import IntegrityError
from flask_limiter import Limiter
import re

app = Flask(__name__)
app.config['SQLALCHEMY_DATABASE_URI'] = 'postgresql://username:password@localhost/dbname'
app.config['JWT_SECRET_KEY'] = 'your_jwt_secret_key'
db = SQLAlchemy(app)
ma = Marshmallow(app)
jwt = JWTManager(app)

limiter = Limiter(
    app,
    key_func=get_jwt_identity,
    default_limits=["5/minute"]
)

class User(db.Model):
    id = db.Column(db.Integer, primary_key=True)
    display_name = db.Column(db.String(30))
    email = db.Column(db.String(120), unique=True)
    bio = db.Column(db.String(160))

class UserSchema(ma.Schema):
    class Meta:
        fields = ("display_name", "email", "bio")

user_schema = UserSchema()
email_regex = re.compile(r'^[^@]+@[^@]+\.[^@]+$')

@app.route('/api/v1/users/me', methods=['PATCH'])
@jwt_required()
@limiter.limit("5/minute")
def update_user():
    user_id = get_jwt_identity()
    user = User.query.get(user_id)
    if not user:
        return jsonify({'error': 'User not found'}), 404

    data = request.get_json()
    if not data:
        return jsonify({'error': 'Invalid JSON payload'}), 400

    errors = user_schema.validate(data, partial=True)
    if errors:
        return jsonify(errors), 400

    if 'display_name' in data:
        if not (3 <= len(data['display_name']) <= 30):
            return jsonify({'error': 'Display name must be between 3 and 30 characters'}), 400
        user.display_name = data['display_name']

    if 'email' in data:
        if not email_regex.match(data['email']):
            return jsonify({'error': 'Invalid email format'}), 400
        existing_user = User.query.filter_by(email=data['email']).first()
        if existing_user:
            return jsonify({'error': 'Email already exists'}), 409
        user.email = data['email']

    if 'bio' in data:
        if len(data['bio']) > 160:
            return jsonify({'error': 'Bio must be 160 characters or fewer'}), 400
        user.bio = data['bio']

    try:
        db.session.commit()
    except IntegrityError:
        db.session.rollback()
        return jsonify({'error': 'Database error'}), 409

    return jsonify(user_schema.dump(user)), 200

if __name__ == '__main__':
    app.run()
