    const response = await axios.get('/api/friend-requests');
    commit('SET_FRIEND_REQUESTS', response.data);
  },
  async fetchFriends({ commit }) {
    const response = await axios.get('/api/friends');
    commit('SET_FRIENDS', response.data);
  },
  async sendRequest({ dispatch }, userId) {
    await axios.post(`/api/send-request/${userId}`);
    dispatch('fetchFriendRequests');
  },
  async cancelRequest({ commit }, userId) {
    await axios.post(`/api/cancel-request/${userId}`);
    commit('REMOVE_REQUEST', userId);
  },
  async acceptRequest({ commit, dispatch }, userId) {
    const response = await axios.post(`/api/accept-request/${userId}`);
    commit('REMOVE_REQUEST', userId);
    commit('ADD_FRIEND', response.data);
    dispatch('fetchFriends');
  }
};

export default {
  namespaced: true,
  state,
  mutations,
  actions
};
