class TrieNode:
    def __init__(self):
        self.children = {}
        self.is_end_of_word = False

class Trie:
    def __init__(self):
        self.root = TrieNode()

    def insert(self, word):
        node = self.root
        for char in word.lower():
            if char not in node.children:
                node.children[char] = TrieNode()
            node = node.children[char]
        node.is_end_of_word = True

    def _search_node(self, prefix):
        node = self.root
        for char in prefix.lower():
            if char not in node.children:
                return None
            node = node.children[char]
        return node

    def search(self, prefix):
        node = self._search_node(prefix)
        if not node:
            return []
        return self._autocomplete(node, prefix.lower())

    def _autocomplete(self, node, prefix):
        words = []
        if node.is_end_of_word:
            words.append(prefix)
        for char, child_node in node.children.items():
            words.extend(self._autocomplete(child_node, prefix + char))
        return words

    def serialize(self):
        def _serialize(node):
            data = {'end': node.is_end_of_word, 'children': {}}
            for char, child in node.children.items():
                data['children'][char] = _serialize(child)
            return data

        return _serialize(self.root)

    @classmethod
    def deserialize(cls, data):
        def _deserialize(data):
            node = TrieNode()
            node.is_end_of_word = data['end']
            for char, child_data in data['children'].items():
                node.children[char] = _deserialize(child_data)
            return node

        trie = cls()
        trie.root = _deserialize(data)
        return trie
