// CMS Hook: File Upload Validation
add_filter('cms_file_upload', 'custom_file_upload_validation');

function custom_file_upload_validation($file) {
    $max_file_size = 2 * 1024 * 1024; // Maximum file size: 2MB
    $allowed_types = ['image/jpeg', 'image/png', 'application/pdf']; // Allowed file types
    $clamav_socket = '/var/run/clamav/clamd.sock'; // ClamAV Unix socket path

    // Check file size
    if ($file['size'] > $max_file_size) {
        return "Error: File size exceeds 2MB limit.";
    }

    // Check allowed file types
    if (!in_array($file['type'], $allowed_types)) {
        return "Error: File type not allowed.";
    }

    // Scan file with ClamAV
    $clamav = socket_create(AF_UNIX, SOCK_STREAM, 0);
    if ($clamav === false || !@socket_connect($clamav, $clamav_socket)) {
        return "Error: Unable to connect to ClamAV.";
    }

    $scan_command = "SCAN " . escapeshellarg($file['tmp_name']);
    socket_write($clamav, $scan_command . "\n");
    $clamav_response = socket_read($clamav, 4096);
    socket_close($clamav);

    if (strpos($clamav_response, 'OK') === false) {
        return "Error: File infected with malware.";
    }

    return true; // File is valid and uploaded safely
}
