const Koa = require('koa');
const Router = require('@koa/router');
const BodyParser = require('koa-bodyparser');
const crypto = require('crypto');
const axios = require('axios');
const rateLimit = require('koa-ratelimit');
const logger = require('koa-logger');

const app = new Koa();
const router = new Router();
const store = new Map();

app.use(logger());

app.use(rateLimit({
  driver: 'memory',
  db: new Map(),
  duration: 60000, // 1 minute
  errorMessage: 'Too many requests, please try again later.',
  max: 100,
  id: (ctx) => ctx.ip,
}));

app.use(BodyParser());

const hmac = (key, data) => {
  return crypto
    .createHmac('sha256', key)
    .update(data)
    .digest('hex');
};

router.post('/webhooks', async (ctx) => {
  const { url, secret } = ctx.request.body;
  if (!url || !secret) {
    ctx.status = 400;
    ctx.body = 'URL and secret are required';
    return;
  }
  const id = crypto.randomBytes(16).toString('hex');
  store.set(id, { url, secret });
  ctx.body = { id };
});

router.get('/webhooks/:id', async (ctx) => {
  const { id } = ctx.params;
  const webhook = store.get(id);
  if (!webhook) {
    ctx.status = 404;
    return;
  }
  ctx.body = webhook;
});

router.put('/webhooks/:id', async (ctx) => {
  const { id } = ctx.params;
  const { url, secret } = ctx.request.body;
  if (!store.has(id)) {
    ctx.status = 404;
    return;
  }
  if (!url || !secret) {
    ctx.status = 400;
    ctx.body = 'URL and secret are required';
    return;
  }
  store.set(id, { url, secret });
  ctx.status = 204;
});

router.delete('/webhooks/:id', async (ctx) => {
  const { id } = ctx.params;
  if (!store.has(id)) {
    ctx.status = 404;
    return;
  }
  store.delete(id);
  ctx.status = 204;
});

const triggerEvent = async (event, data) => {
  store.forEach(async (webhook, id) => {
    try {
      const payload = JSON.stringify({ event, data });
      const signature = hmac(webhook.secret, payload);

      await axios.post(webhook.url, payload, {
        headers: {
          'Content-Type': 'application/json',
          'X-Hub-Signature': `sha256=${signature}`,
        },
      });
    } catch (error) {
      console.error(`Error triggering webhook ${id}:`, error);
    }
  });
};

app.use(router.routes()).use(router.allowedMethods());

app.listen(3000, () => {
  console.log('Webhook service running on port 3000');
});
