import stripe

class StripePaymentProcessor:
    def __init__(self, api_key):
        self.api_key = api_key
        stripe.api_key = self.api_key

    def process_payment(self, amount, currency, source, description=None):
        try:
            charge = stripe.Charge.create(
                amount=amount,
                currency=currency,
                source=source,
                description=description
            )
            return {"success": True, "charge_id": charge.id}
        except stripe.error.CardError as e:
            return {"success": False, "error": "Card declined: " + str(e)}
        except stripe.error.RateLimitError:
            return {"success": False, "error": "Rate limit exceeded, please try again later."}
        except stripe.error.InvalidRequestError:
            return {"success": False, "error": "Invalid request, check your parameters."}
        except stripe.error.AuthenticationError:
            return {"success": False, "error": "Authentication with Stripe failed."}
        except stripe.error.APIConnectionError:
            return {"success": False, "error": "Network error, please try again."}
        except stripe.error.StripeError as e:
            return {"success": False, "error": "Stripe error: " + str(e)}
        except Exception as e:
            return {"success": False, "error": "An unexpected error occurred: " + str(e)}


