from flask import Flask, render_template, request, send_file
from flask_sqlalchemy import SQLAlchemy
from io import BytesIO
import csv
from fpdf import FPDF

app = Flask(__name__)
app.config['SQLALCHEMY_DATABASE_URI'] = 'sqlite:///crm.db'
db = SQLAlchemy(app)

class Customer(db.Model):
    id = db.Column(db.Integer, primary_key=True)
    name = db.Column(db.String(100))
    contact_details = db.Column(db.String(200))
    last_purchase_date = db.Column(db.Date)
    total_spend = db.Column(db.Float)

@app.route('/generate_report')
def generate_report():
    format = request.args.get('format')
    customers = Customer.query.all()

    if format == 'csv':
        return create_csv(customers)
    elif format == 'pdf':
        return create_pdf(customers)
    else:
        return "Invalid format", 400

def create_csv(customers):
    si = BytesIO()
    cw = csv.writer(si)
    cw.writerow(['Customer Name', 'Contact Details', 'Last Purchase Date', 'Total Spend'])

    for customer in customers:
        cw.writerow([customer.name, customer.contact_details, customer.last_purchase_date, customer.total_spend])

    si.seek(0)
    return send_file(si, mimetype='text/csv', as_attachment=True, attachment_filename='customers_report.csv')

class PDF(FPDF):
    def header(self):
        self.set_font('Arial', 'B', 12)
        self.cell(0, 10, 'Customer Report', ln=True, align='C')

    def footer(self):
        self.set_y(-15)
        self.set_font('Arial', 'I', 8)
        self.cell(0, 10, f'Page {self.page_no()}', 0, 0, 'C')

def create_pdf(customers):
    pdf = PDF()
    pdf.add_page()
    pdf.set_font("Arial", size=12)

    for customer in customers:
        pdf.cell(0, 10, f"Name: {customer.name}, Contact Details: {customer.contact_details}, "
                        f"Last Purchase Date: {customer.last_purchase_date}, Total Spend: {customer.total_spend}",
                 ln=True)

    pdf_output = BytesIO()
    pdf.output(pdf_output)
    pdf_output.seek(0)
    return send_file(pdf_output, mimetype='application/pdf', as_attachment=True, attachment_filename='customers_report.pdf')

# Unit Tests
import unittest

class TestReportGeneration(unittest.TestCase):
    def setUp(self):
        self.app = app.test_client()
