        v0 = self.parameters.get('initial_velocity', 0)
        angle = np.radians(self.parameters.get('angle', 45))
        g = 9.81  # gravity
        time_of_flight = (2 * v0 * np.sin(angle)) / g
        distance_traveled = (v0**2) * np.sin(2 * angle) / g

        self.results = {
            'time_of_flight': time_of_flight,
            'distance_traveled': distance_traveled
        }

    def get_results(self):
        return self.results

    @staticmethod
    def compare_experiments(exp1, exp2, based_on='parameters'):
        if based_on == 'parameters':
            return exp1.parameters == exp2.parameters
        elif based_on == 'results':
