// payments.service.ts
import { Injectable, BadRequestException, HttpException, HttpStatus } from '@nestjs/common';
import { InjectModel } from '@nestjs/mongoose';
import { Model } from 'mongoose';
import { CreatePaymentDto } from './dto/create-payment.dto';
import { Payment } from './schemas/payment.schema';
import { ClientSession } from 'mongoose';
import { Stripe } from 'stripe';

@Injectable()
export class PaymentsService {
  constructor(
    @InjectModel(Payment.name) private readonly paymentModel: Model<Payment>,
    private readonly stripe: Stripe
  ) {}

  async createPayment(createPaymentDto: CreatePaymentDto) {
    const session: ClientSession = await this.paymentModel.startSession();
    session.startTransaction();

    try {
      const payment = new this.paymentModel(createPaymentDto);
      await payment.save({ session });

      const paymentIntent = await this.stripe.paymentIntents.create({
        amount: createPaymentDto.amount,
        currency: createPaymentDto.currency,
      });

      payment.stripePaymentIntentId = paymentIntent.id;
      await payment.save({ session });

      await session.commitTransaction();

      return { paymentId: payment.id, clientSecret: paymentIntent.client_secret };
    } catch (error) {
      await session.abortTransaction();
      console.error('Payment processing error:', error);
      throw new HttpException(
        { error: 'Payment gateway error', details: error.message || error },
        HttpStatus.BAD_GATEWAY
      );
    } finally {
      session.endSession();
    }
  }
}
