    conditions = data.get('conditions')

    if not name or not isinstance(name, str):
        return jsonify({"error": "Invalid or missing 'name'"}), 400
    if not isinstance(age, int) or age < 0:
        return jsonify({"error": "Invalid or missing 'age'"}), 400
    if not isinstance(conditions, list) or not all(isinstance(cond, str) for cond in conditions):
        return jsonify({"error": "Invalid or missing 'conditions'"}), 400

    # Validate each condition
    if not all(cond in VALID_CONDITIONS for cond in conditions):
        return jsonify({"error": "One or more conditions are invalid"}), 400

    # Update patient record
    result = patients_collection.update_one(
        {"_id": ObjectId(patient_id)},
        {"$set": {
            "name": name,
            "age": age,
            "conditions": conditions
        }}
    )

    if result.matched_count == 0:
        return jsonify({"error": "Patient not found"}), 404

    # Fetch the updated patient record
    updated_patient = patients_collection.find_one({"_id": ObjectId(patient_id)})

    return jsonify({
        "id": str(updated_patient["_id"]),
        "name": updated_patient["name"],
        "age": updated_patient["age"],
        "conditions": updated_patient["conditions"]
    }), 200

if __name__ == '__main__':
    app.run(debug=True)
