                'actions': ['move to hall']
            }
        }
        # Starting room for the player
        self.current_room = 'hall'
        # Inventory to store items player collects
        self.inventory = []

    def save_game(self, filename='savegame.json'):
        # Save the current game state to a JSON file
        with open(filename, 'w') as file:
            json.dump({
                'current_room': self.current_room,
                'inventory': self.inventory
            }, file)

    def load_game(self, filename='savegame.json'):
        # Load the game state from a JSON file
        with open(filename, 'r') as file:
            data = json.load(file)
            self.current_room = data['current_room']
            self.inventory = data['inventory']

    def display_current_room(self):
        # Display the current room's description and actions
        room = self.rooms[self.current_room]
        print(f"Room: {self.current_room.upper()}")
        print(room['description'])
        print("Items available:", room['items'])
        print("Actions:", room['actions'])

    def play(self):
        # Main game loop
        while True:
            self.display_current_room()
            action = input("Enter your action: ").lower()
            if action == 'save':
                self.save_game()
                print("Game saved.")
            elif action == 'load':
                self.load_game()
                print("Game loaded.")
            elif action.startswith('move to '):
                new_room = action.split('move to ')[1]
                if new_room in self.rooms[self.current_room]['actions']:
                    self.current_room = new_room
                else:
                    print("You cannot move there.")
            elif action in self.rooms[self.current_room]['items']:
                # Pick up the item
                self.inventory.append(action)
                self.rooms[self.current_room]['items'].remove(action)
                print(f"Picked up {action}.")
            elif action == 'quit':
                break
            else:
                print("Invalid action.")

# Instantiate and run the game
game = AdventureGame()
