const express = require('express');
const app = express();
const fs = require('fs');
const blockedIPs = new Set();
let ipRequestCounts = {};

// Middleware for rate limiting and IP blocking
function rateLimiter(req, res, next) {
    const ip = req.ip;
    const now = Date.now();
    const windowSize = 15 * 60 * 1000; // 15 minutes
    const requestLimit = 100; // Adjust the request limit as necessary

    // Clean up old requests
    for (const [trackedIp, requests] of Object.entries(ipRequestCounts)) {
        ipRequestCounts[trackedIp] = requests.filter(timestamp => now - timestamp <= windowSize);
        if (ipRequestCounts[trackedIp].length === 0) {
            delete ipRequestCounts[trackedIp];
        }
    }

    // Block IP if it has exceeded request limit
    if (blockedIPs.has(ip)) {
        logBlockedIP(ip);
        return res.status(429).send('Too many requests - try again later.');
    }

    if (!ipRequestCounts[ip]) {
        ipRequestCounts[ip] = [];
    }

    ipRequestCounts[ip].push(now);

    if (ipRequestCounts[ip].length > requestLimit) {
        blockedIPs.add(ip);
        logBlockedIP(ip);
        return res.status(429).send('Too many requests - try again later.');
    }

    next();
}

function logBlockedIP(ip) {
    const logMessage = `${new Date().toISOString()} - Blocked IP: ${ip}\n`;
    fs.appendFile('blocked-ips.log', logMessage, err => {
        if (err) console.error('Failed to log blocked IP:', err);
    });
}

// Administrator interface to review and manage blocked IPs
app.get('/admin/blocked-ips', (req, res) => {
    res.json(Array.from(blockedIPs));
});

app.delete('/admin/blocked-ips', (req, res) => {
    const ip = req.body.ip;
    if (blockedIPs.has(ip)) {
        blockedIPs.delete(ip);
        res.send(`IP ${ip} has been unblocked.`);
    } else {
        res.status(404).send('IP not found in blocked list.');
    }
});

app.use(rateLimiter);

app.get('/', (req, res) => {
    res.send('Hello World');
});

app.listen(3000, () => {
    console.log('Server listening on port 3000');
});
