using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.Caching.Memory;
using Microsoft.Extensions.Logging;
using Microsoft.Extensions.Options;
using System;
using System.Net.Http;
using System.Text.Json;
using System.Threading.Tasks;
using Polly;
using Polly.Extensions.Http;
using System.ComponentModel.DataAnnotations;
using Microsoft.OpenApi.Models;
using Swashbuckle.AspNetCore.Annotations;
using Microsoft.AspNetCore.Authorization;

namespace CurrencyConversionService.Controllers
{
    [ApiController]
    [Route("[controller]")]
    public class ConvertController : ControllerBase
    {
        private readonly IHttpClientFactory _httpClientFactory;
        private readonly IMemoryCache _cache;
        private readonly ILogger<ConvertController> _logger;
        private readonly IOptions<ApiSettings> _settings;

        public ConvertController(IHttpClientFactory httpClientFactory, IMemoryCache cache, ILogger<ConvertController> logger, IOptions<ApiSettings> settings)
        {
            _httpClientFactory = httpClientFactory;
            _cache = cache;
            _logger = logger;
            _settings = settings;
        }

        [HttpGet]
        [Authorize]
        [SwaggerOperation(Summary = "Convert currency", Description = "Converts an amount from one currency to another using the latest exchange rate.")]
        [SwaggerResponse(200, "Conversion successful", typeof(ConvertResponse))]
        [SwaggerResponse(400, "Invalid input", typeof(ErrorResponse))]
        [SwaggerResponse(401, "Unauthorized access", typeof(ErrorResponse))]
        [SwaggerResponse(503, "Service unavailable", typeof(ErrorResponse))]
        public async Task<IActionResult> Get(
            [FromQuery, Required, StringLength(3, MinimumLength = 3)] string fromCurrency,
            [FromQuery, Required, StringLength(3, MinimumLength = 3)] string toCurrency,
            [FromQuery, Required, Range(0.01, double.MaxValue)] decimal amount)
        {
            string correlationId = Guid.NewGuid().ToString();
            HttpContext.Request.Headers.TryGetValue("X-Api-Key", out var apiKey);
            if (_settings.Value.ApiKey != apiKey)
            {
                return Unauthorized(new ErrorResponse { Error = "Unauthorized", Details = "Invalid API key" });
            }

            _logger.LogInformation($"Request: {new { fromCurrency, toCurrency, amount, correlationId }}");

            var key = $"{fromCurrency}_{toCurrency}";
            if (!_cache.TryGetValue(key, out decimal exchangeRate))
            {
                try
                {
                    var client = _httpClientFactory.CreateClient();
                    var policy = HttpPolicyExtensions
                        .HandleTransientHttpError()
                        .WaitAndRetryAsync(3, retryAttempt => TimeSpan.FromSeconds(Math.Pow(2, retryAttempt)));

                    var response = await policy.ExecuteAsync(() =>
                        client.GetAsync($"https://api.exchangeratesapi.io/latest?base={fromCurrency}&symbols={toCurrency}"));

                    if (!response.IsSuccessStatusCode)
                    {
                        throw new Exception("External API call failed.");
                    }

                    var content = await response.Content.ReadAsStringAsync();
                    var rateResponse = JsonSerializer.Deserialize<ExchangeRateResponse>(content);

                    exchangeRate = rateResponse.Rates[toCurrency];
                    _cache.Set(key, exchangeRate, TimeSpan.FromMinutes(5));
                }
                catch (Exception ex)
                {
                    _logger.LogError(ex, "Error fetching exchange rate");
                    return StatusCode(503, new ErrorResponse { Error = "Rate service unavailable", Details = ex.Message });
                }
            }

            var convertedAmount = amount * exchangeRate;
            var result = new ConvertResponse
            {
                FromCurrency = fromCurrency,
                ToCurrency = toCurrency,
                ExchangeRate = exchangeRate,
                OriginalAmount = amount,
                ConvertedAmount = convertedAmount,
                Timestamp = DateTime.UtcNow
            };

            _logger.LogInformation($"Response: {result} with correlationId: {correlationId}");
            return Ok(result);
        }
    }

    public class ConvertResponse
    {
        public string FromCurrency { get; set; }
        public string ToCurrency { get; set; }
        public decimal ExchangeRate { get; set; }
        public decimal OriginalAmount { get; set; }
        public decimal ConvertedAmount { get; set; }
        public DateTime Timestamp { get; set; }
    }

    public class ExchangeRateResponse
    {
        public Dictionary<string, decimal> Rates { get; set; }
    }

    public class ErrorResponse
    {
        public string Error { get; set; }
        public string Details { get; set; }
    }

    public class ApiSettings
    {
        public string ApiKey { get; set; }
    }
}
