        productName VARCHAR(255) NOT NULL
      );
    `);
    await connection.query(`
      CREATE TABLE IF NOT EXISTS reviews (
        reviewID INT AUTO_INCREMENT PRIMARY KEY,
        productID INT,
        userID INT,
        rating INT,
        comment TEXT,
        FOREIGN KEY (productID) REFERENCES products(productID),
