app.post('/reviews', [
  body('productID').isInt(),
  body('userID').isInt(),
  body('rating').isInt({ min: 1, max: 5 }),
  body('comment').isString()
], async (req, res) => {
  const errors = validationResult(req);
  if (!errors.isEmpty()) {
