import csv

def read_tasks_from_csv(file_path):
    tasks = []
    with open(file_path, mode='r', newline='') as csvfile:
        reader = csv.DictReader(csvfile)
        for row in reader:
            task = {
                'name': row['task_name'],
                'priority': int(row['priority']),
                'duration': int(row['duration'])
            }
            tasks.append(task)
    return tasks

def schedule_tasks(tasks):
    return sorted(tasks, key=lambda x: (x['priority'], x['duration']))

def print_schedule(task_schedule):
    for task in task_schedule:
        print(f"Task: {task['name']}, Priority: {task['priority']}, Duration: {task['duration']}")

def main():
    file_path = 'tasks.csv'
    tasks = read_tasks_from_csv(file_path)
    scheduled_tasks = schedule_tasks(tasks)
    print_schedule(scheduled_tasks)

if __name__ == "__main__":
    main()
